            Some(mut node_box) => {
                if key.len() == 0 {
                    // Current node is the endpoint for the key.
                    node_box.is_end = false;
                    // Assist Verus in verifying that containment only changed for the empty key.
                    assert(forall |k: Seq<u8>| node_box.contains(k) <==> old_tree.unwrap().contains(k) && k != key@);
